import { z } from 'zod';
import { Request, Response, NextFunction } from 'express';

const createUserSchema = z.object({
  email: z.string().email(),
  age: z.coerce.number().int().min(13),
});

function validate(schema: z.ZodTypeAny) {
  return (req: Request, res: Response, next: NextFunction) => {
    const result = schema.safeParse(req.body);
    if (!result.success) {
      res.status(422).json({ errors: result.error.issues });
      return;
    }
    req.body = result.data;
    next();
  };
}

router.post('/users', validate(createUserSchema), createUser);

import jwt from 'jsonwebtoken';
import type { Request, Response, NextFunction } from 'express';

declare global {
  namespace Express {
    interface Request { user?: jwt.JwtPayload; }
  }
}

export function authenticate(req: Request, res: Response, next: NextFunction) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Missing token' });

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET!, {
      algorithms: ['HS256'],
    }) as jwt.JwtPayload;
    next();
  } catch (err) {
    next(Object.assign(new Error('Invalid token'), { status: 401 }));
  }
}

// errors/handler.js
function errorHandler(err, req, res, next) {
  const status = err.status ?? err.statusCode ?? 500;
  const isProd = process.env.NODE_ENV === 'production';

  res.status(status).json({
    status,
    code: err.code ?? 'INTERNAL_ERROR',
    message: err.message ?? 'Something went wrong',
    ...(isProd ? {} : { stack: err.stack }),
  });
}

// app.js — must be last, after all routes
app.use(errorHandler);

// ❌ N+1 — fires one extra query per post inside the route handler
app.get('/posts', async (req, res) => {
  const posts = await prisma.post.findMany();
  const withAuthors = await Promise.all(
    posts.map(p => prisma.user.findUnique({ where: { id: p.authorId } }))
  );
  res.json(withAuthors);
});

// ✅ Single JOIN via eager load — one round-trip regardless of result size
app.get('/posts', async (req, res) => {
  const posts = await prisma.post.findMany({
    include: { author: { select: { id: true, name: true } } }
  });
  res.json(posts);
});

